mapper.select:
SELECT c.CLAIM_NO as claimNo, c.MEMBER_ID as memberId, m.USERNAME as memberName, c.POLICY_NO as policyNo, c.CLAIM_AMOUNT as claimAmount, c.APPROVE_AMOUNT as approveAmount, c.CLAIM_STATUS as claimStatus, c.AGENT_ID as agentId, c.APPLY_TIME as applyTime, c.EXPIRY_TIME as expiryTime, c.SETTLE_TIME as settleTime, c.REMARK as remark, c.UPDATE_USER as updateUser, c.FILE_01_NAME as file01Name, c.FILE_01_PATH as file01Path, c.FILE_02_NAME as file02Name, c.FILE_02_PATH as file02Path FROM tb_claim c LEFT JOIN tb_cust_user m ON c.MEMBER_ID = m.MEMBER_ID
AND c.CLAIM_STATUS = #{status}
AND c.POLICY_NO LIKE CONCAT('%', #{policyNo}, '%')
AND DATE(c.APPLY_TIME) = #{applyDate}
ORDER BY c.APPLY_TIME DESC

mapper.insert:
INSERT INTO tb_claim (
    CLAIM_NO, MEMBER_ID, POLICY_NO, CLAIM_AMOUNT, APPROVE_AMOUNT, 
    CLAIM_STATUS, AGENT_ID, APPLY_TIME, EXPIRY_TIME, REMARK, UPDATE_USER,
    FILE_01_NAME, FILE_01_PATH, FILE_02_NAME, FILE_02_PATH
) VALUES (
    #{claimNo}, #{memberId}, #{policyNo}, #{claimAmount}, #{approveAmount}, 
    #{claimStatus}, #{agentId}, #{applyTime}, #{expiryTime}, #{remark}, #{updateUser},
    #{file01Name}, #{file01Path}, #{file02Name}, #{file02Path}
)

mapper.update:
UPDATE tb_claim
CLAIM_AMOUNT = #{claimAmount}, APPROVE_AMOUNT = #{approveAmount}, CLAIM_STATUS = #{claimStatus}, REMARK = #{remark}, UPDATE_USER = #{updateUser}, FILE_01_NAME = #{file01Name}, FILE_01_PATH = #{file01Path}, FILE_02_NAME = #{file02Name}, FILE_02_PATH = #{file02Path}, SETTLE_TIME = NOW(),
WHERE CLAIM_NO = #{claimNo}

